import threading
import functools
from typing import Callable

def cached(cache: dict, key: Callable = hash, lock: threading.Lock = None) -> Callable:
    """Decorator to wrap a function with a memoizing callable that saves
    results in a cache.

    Args:
        cache (dict): A dictionary to store cached results.
        key (Callable, optional): A function to generate the cache key. Defaults to hash.
        lock (threading.Lock, optional): A threading lock for thread safety. Defaults to None.

    Returns:
        Callable: A decorator function that can be applied to any callable to cache its results.
    """

    def decorator(func: Callable) -> Callable:
        """Inner decorator function that wraps the target function.

        Args:
            func (Callable): The function to be decorated.

        Returns:
            Callable: The wrapper function that implements caching logic.
        """

        if cache is None:
            def wrapper(*args, **kwargs):
                """Wrapper function that directly calls the function if no cache is provided."""
                return func(*args, **kwargs)
        elif lock is None:
            def wrapper(*args, **kwargs):
                """Wrapper function that handles caching without a lock."""
                k = key(*args, **kwargs)
                try:
                    return cache[k]
                except KeyError:
                    pass  # key not found
                v = func(*args, **kwargs)
                try:
                    cache[k] = v
                except ValueError:
                    pass  # value too large
                return v
        else:
            def wrapper(*args, **kwargs):
                """Wrapper function that handles caching with a lock."""
                k = key(*args, **kwargs)
                try:
                    with lock:
                        return cache[k]
                except KeyError:
                    pass  # key not found
                v = func(*args, **kwargs)
                try:
                    with lock:
                        return cache.setdefault(k, v)
                except ValueError:
                    return v  # value too large

        return functools.update_wrapper(wrapper, func)

    return decorator

