import re
import sys

def split(s: str, platform: str = 'this') -> list[str]:
    """Split the input str under given platform, return the splitting result.
    If platform equals 'this', auto-detect current platform.
    If platform equals '1', use POSIX style.
    If platform equals '0', use Windows/CMD style.

    Args:
        s: input str (str)
        platform: 'this' = auto from current platform (str);
                  '1' = POSIX (str);
                  '0' = Windows/CMD (str)

    Returns:
        a list of splitting str (list[str])
    """
    # Determine platform if 'this' is specified
    if platform == 'this':
        platform = (sys.platform != 'win32')

    # Define regular expression for command-line parsing based on platform
    if platform == 1:
        RE_CMD_LEX = r'''\"((?:\\\\[\"\\\\]|[^\"])*)\"|'([^']*)'|(\\\\.)|(&&?|\\|\\|?|\\d?\\>|[<])|([^\\s'\"\\\\&|<>]+)|(\\s+)|(.)'''
    elif platform == 0:
        RE_CMD_LEX = r'''\"((?:\"\"|\\\\[\"\\\\]|[^\"])*)\"?()|(\\\\\\\\(?=\\\\*\")|\\\\\")|(&&?|\\|\\|?|\\d?>|[<])|([^\\s\"&|<>]+)|(\\s+)|(.)'''
    else:
        raise AssertionError('unknown platform %r' % platform)

    # Initialize list for arguments and accumulator for argument pieces
    args = []
    accu = None  # collects pieces of one arg

    # Iterate through matches in the input string
    for qs, qss, esc, pipe, word, white, fail in re.findall(RE_CMD_LEX, s):
        if word:
            pass  # most frequent case
        elif esc:
            word = esc[1]
        elif white or pipe:
            if accu is not None:
                args.append(accu)
            if pipe:
                args.append(pipe)
            accu = None
            continue
        elif fail:
            raise ValueError("invalid or incomplete shell string")
        elif qs:
            word = qs.replace('\\\\\"', '\"').replace('\\\\\\\\', '\\\\')
            if platform == 0:
                word = word.replace('\"\"', '\"')
        else:
            word = qss  # may be even empty; must be last

        # Accumulate the argument pieces
        if accu is None:
            accu = word
        else:
            accu += word

    # Append any remaining accumulated argument
    if accu is not None:
        args.append(accu)

    return args

