from timeout_decorator import timeout, TimeoutError as TimeoutDecoratorError

def unit_of_work(metadata: Optional[dict] = None, timeout: Optional[int] = None) -> Callable:
    """A decorator that adds metadata and enforces a timeout on the wrapped function.

    Args:
        metadata (Optional[dict]): A dictionary containing metadata attributes (optional).
        timeout (Optional[int]): An integer specifying the maximum execution time in seconds (optional).

    Returns:
        Callable: A decorator that can be applied to a function, adding metadata and enforcing a timeout.
    """

    def decorator(func: Callable) -> Callable:
        # Apply timeout if specified
        if timeout is not None:
            func = timeout(timeout)(func)

        # Add metadata to the function
        func.metadata = metadata if metadata is not None else {}

        @wraps(func)
        def wrapper(*args, **kwargs):
            try:
                return func(*args, **kwargs)
            except TimeoutDecoratorError:
                raise TimeoutError(f"The function '{func.__name__}' exceeded the timeout of {timeout} seconds.")

        return wrapper

    return decorator

