def check_dict_case(input_dict: dict) -> bool:
    """Check if all keys in the dictionary are either all uppercase or all lowercase.

    Args:
        input_dict (dict): The dictionary to check.

    Returns:
        bool: True if all keys are consistently cased, False otherwise.
    """
    if len(input_dict.keys()) == 0:
        return False

    state = "start"

    for key in input_dict.keys():
        if isinstance(key, str) == False:
            state = "mixed"
            break

        if state == "start":
            if key.isupper():
                state = "upper"
            elif key.islower():
                state = "lower"
            else:
                break
        elif (state == "upper" and not key.isupper()) or (state == "lower" and not key.islower()):
            state = "mixed"
            break

    return state == "upper" or state == "lower"

