def fix_spaces(text: str) -> str:
    """Transforms spaces in the input string according to specific rules.

    Args:
        text (str): The input string containing spaces to be transformed.

    Returns:
        str: The transformed string with spaces replaced according to the rules.
    """
    new_text = ""
    start = 0

    for i, char in enumerate(text):
        if char == " ":
            continue
        else:
            num_spaces = i - start
            if num_spaces > 2:
                new_text += "-" + char
            elif num_spaces > 0:
                new_text += "_" * num_spaces + char
            else:
                new_text += char
            start = i + 1

    # Handle trailing spaces
    if len(text) - start > 2:
        new_text += "-"
    elif len(text) - start > 0:
        new_text += "_"

    return new_text

