def group_tuples(tuples_list: list[tuple[str, str]]) -> list[tuple[str, str]]:
    """
    Groups tuples by their first element.

    Args:
        tuples_list (list[tuple[str, str]]): A list of tuples where each tuple contains two strings.

    Returns:
        list[tuple[str, str]]: A list of grouped tuples.
    """
    out = {}

    for elem in tuples_list:
        try:
            out[elem[0]].extend(elem[1:])
        except KeyError:
            out[elem[0]] = list(elem)

    return [tuple(values) for values in out.values()]

