from typing import List, Tuple
from collections import defaultdict

class Maze:
    def __init__(self, n: int, illusion_rates: List[int], tunnels: List[Tuple[int, int]]):
        self.n = n
        self.illusion_rates = illusion_rates
        self.graph = defaultdict(list)
        self.build_graph(tunnels)

    def build_graph(self, tunnels: List[Tuple[int, int]]) -> None:
        """Builds the adjacency list for the maze."""
        for s, t in tunnels:
            self.graph[s].append(t)
            self.graph[t].append(s)

    def update_illusion_rate(self, u: int, c: int) -> None:
        """Updates the illusion rate of room u to c."""
        self.illusion_rates[u - 1] = c

    def calculate_min_energy(self, u: int, v: int) -> int:
        """Calculates the minimum energy needed to travel from room u to room v."""
        visited = [False] * (self.n + 1)
        return self.dfs(u, v, visited)

    def dfs(self, current: int, target: int, visited: List[bool]) -> int:
        """Performs DFS to find the path and calculate energy."""
        if current == target:
            return 0

        visited[current] = True
        min_energy = float('inf')

        for neighbor in self.graph[current]:
            if not visited[neighbor]:
                energy = self.calculate_energy(current, neighbor)
                total_energy = energy + self.dfs(neighbor, target, visited)
                min_energy = min(min_energy, total_energy)

        visited[current] = False
        return min_energy

    def calculate_energy(self, x: int, y: int) -> int:
        """Calculates the energy required to travel between rooms x and y."""
        return max(abs(self.illusion_rates[x - 1] + self.illusion_rates[y - 1]),
                   abs(self.illusion_rates[x - 1] - self.illusion_rates[y - 1]))

def main():
    n, q = map(int, input().split())  # Read number of rooms and queries
    illusion_rates = list(map(int, input().split()))  # Read initial illusion rates
    tunnels = [tuple(map(int, input().split())) for _ in range(n - 1)]  # Read tunnels

    maze = Maze(n, illusion_rates, tunnels)

    for _ in range(q):
        query = list(map(int, input().split()))  # Read queries
        if query[0] == 1:
            maze.update_illusion_rate(query[1], query[2])  # Update illusion rate
        elif query[0] == 2:
            result = maze.calculate_min_energy(query[1], query[2])  # Calculate energy
            print(result)  # Output result

if __name__ == "__main__":
    main()

